class Solution {
public:
    int longestDecomposition(string text) {
        int n = text.size();
        int l = 0, r = n - 1;
        int count = 0;
        string left = "", right = "";
        while (l <= r) {
            left += text[l];
            right = text[r] + right;
            if (left == right) {
                count += 2;
                left = "", right = "";
            }
            l++, r--;
        }
        if (left.size() > 0) count--;
        return count + (l > r);
    }
};
```
